-- Seed academy_guides from the original src/content/academy.ts GUIDES array.
-- Idempotent: on conflict (slug) refresh content so re-runs stay in sync.
on conflict (slug) do update set
  category = excluded.category, level = excluded.level, title = excluded.title,
  title_en = excluded.title_en, excerpt = excluded.excerpt, read_min = excluded.read_min,
  emoji = excluded.emoji, blocks = excluded.blocks, sort_order = excluded.sort_order,
  updated_at = now();
